import { Injectable } from '@angular/core';
import { HttpRequest, HttpResponse, HttpHandler, HttpEvent, HttpInterceptor, HTTP_INTERCEPTORS } from '@angular/common/http';
import { Observable, of, throwError } from 'rxjs';
import { delay, materialize, dematerialize } from 'rxjs/operators';
import { AlertService } from '@app/_services';
import { Role } from '@app/_models';

const accountsKey = 'angular-auth-boilerplate-accounts';
let accounts: any[] = JSON.parse(localStorage.getItem(accountsKey) || '[]');

@Injectable()
export class FakeBackendInterceptor implements HttpInterceptor {
  constructor(private alertService: AlertService) { }

  intercept(request: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>> {
    const { url, method, headers, body } = request;

    return handleRoute();

    function handleRoute(): Observable<HttpEvent<any>> {
      switch (true) {
        case url.endsWith('/accounts/authenticate') && method === 'POST': return authenticate();
        case url.endsWith('/accounts/refresh-token') && method === 'POST': return refreshToken();
        case url.endsWith('/accounts/revoke-token') && method === 'POST': return revokeToken();
        case url.endsWith('/accounts/register') && method === 'POST': return register();
        case url.endsWith('/accounts/verify-email') && method === 'POST': return verifyEmail();
        case url.endsWith('/accounts/forgot-password') && method === 'POST': return forgotPassword();
        case url.endsWith('/accounts/validate-reset-token') && method === 'POST': return validateResetToken();
        case url.endsWith('/accounts/reset-password') && method === 'POST': return resetPassword();
        case url.endsWith('/accounts') && method === 'GET': return getAccounts();
        case url.match(/\/accounts\/\d+$/) && method === 'GET': return getAccountById();
        case url.match(/\/accounts\/\d+$/) && method === 'PUT': return updateAccount();
        case url.match(/\/accounts\/\d+$/) && method === 'DELETE': return deleteAccount();
        default: return next.handle(request);
      }
    }

    function authenticate(): Observable<HttpEvent<any>> {
      const { email, password } = body;
      const account = accounts.find(x => x.email === email && x.password === password && x.isVerified);
      if (!account) return error('Email or password is incorrect');
      account.refreshTokens = account.refreshTokens || [];
      account.refreshTokens.push(generateRefreshToken());
      localStorage.setItem(accountsKey, JSON.stringify(accounts));
      return ok({
        ...basicDetails(account),
        jwtToken: generateJwtToken(account)
      });
    }

    function refreshToken(): Observable<HttpEvent<any>> {
      const refreshToken = getRefreshToken();
      if (!refreshToken) return unauthorized();
      const account = accounts.find(x => x.refreshTokens?.includes(refreshToken));
      if (!account) return unauthorized();
      account.refreshTokens = account.refreshTokens.filter((x: string) => x !== refreshToken);
      account.refreshTokens.push(generateRefreshToken());
      localStorage.setItem(accountsKey, JSON.stringify(accounts));
      return ok({
        ...basicDetails(account),
        jwtToken: generateJwtToken(account)
      });
    }

    function revokeToken(): Observable<HttpEvent<any>> {
      const refreshToken = getRefreshToken();
      const account = accounts.find(x => x.refreshTokens?.includes(refreshToken));
      if (account) {
        account.refreshTokens = account.refreshTokens.filter((x: string) => x !== refreshToken);
        localStorage.setItem(accountsKey, JSON.stringify(accounts));
      }
      return ok({});
    }

    function register(): Observable<HttpEvent<any>> {
      const account = body;
      if (accounts.find(x => x.email === account.email)) {
        setTimeout(() => {
          // alertService.info is called from component context; simulate email
        });
        return ok({});
      }
      account.id = newAccountId();
      account.role = accounts.length === 0 ? Role.Admin : Role.User;
      account.isVerified = false;
      account.verificationToken = newToken();
      account.refreshTokens = [];
      accounts.push(account);
      localStorage.setItem(accountsKey, JSON.stringify(accounts));

      // Simulate email display
      const verifyUrl = `${location.origin}/account/verify-email?token=${account.verificationToken}`;
      console.info(`
=== FAKE EMAIL: Verify Account ===
Hi ${account.firstName},
Please verify your email by clicking the link below:
${verifyUrl}
=================================`);

      return ok({});
    }

    function verifyEmail(): Observable<HttpEvent<any>> {
      const { token } = body;
      const account = accounts.find(x => x.verificationToken === token);
      if (!account) return error('Verification failed');
      account.isVerified = true;
      localStorage.setItem(accountsKey, JSON.stringify(accounts));
      return ok({});
    }

    function forgotPassword(): Observable<HttpEvent<any>> {
      const { email } = body;
      const account = accounts.find(x => x.email === email);
      if (!account) return ok({});
      account.resetToken = newToken();
      account.resetTokenExpires = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();
      localStorage.setItem(accountsKey, JSON.stringify(accounts));

      const resetUrl = `${location.origin}/account/reset-password?token=${account.resetToken}`;
      console.info(`
=== FAKE EMAIL: Reset Password ===
Hi ${account.firstName},
Reset your password by clicking the link below:
${resetUrl}
=================================`);

      return ok({});
    }

    function validateResetToken(): Observable<HttpEvent<any>> {
      const { token } = body;
      const account = accounts.find(x =>
        x.resetToken === token &&
        new Date() < new Date(x.resetTokenExpires)
      );
      if (!account) return error('Invalid token');
      return ok({});
    }

    function resetPassword(): Observable<HttpEvent<any>> {
      const { token, password } = body;
      const account = accounts.find(x =>
        x.resetToken === token &&
        new Date() < new Date(x.resetTokenExpires)
      );
      if (!account) return error('Invalid token');
      account.password = password;
      account.isVerified = true;
      delete account.resetToken;
      delete account.resetTokenExpires;
      localStorage.setItem(accountsKey, JSON.stringify(accounts));
      return ok({});
    }

    function getAccounts(): Observable<HttpEvent<any>> {
      if (!isAdmin()) return unauthorized();
      return ok(accounts.map(x => basicDetails(x)));
    }

    function getAccountById(): Observable<HttpEvent<any>> {
      const account = accounts.find(x => x.id === idFromUrl());
      return ok(basicDetails(account));
    }

    function updateAccount(): Observable<HttpEvent<any>> {
      const { body: params } = request;
      let account = accounts.find(x => x.id === idFromUrl());
      Object.assign(account, params);
      if (!params.password) delete account.password;
      localStorage.setItem(accountsKey, JSON.stringify(accounts));
      return ok(basicDetails(account));
    }

    function deleteAccount(): Observable<HttpEvent<any>> {
      accounts = accounts.filter(x => x.id !== idFromUrl());
      localStorage.setItem(accountsKey, JSON.stringify(accounts));
      return ok({});
    }

    // helpers
    function ok(body?: any): Observable<HttpEvent<any>> {
      return of(new HttpResponse({ status: 200, body })).pipe(delay(500));
    }

    function error(message: string): Observable<HttpEvent<any>> {
      return throwError(() => ({ error: { message } })).pipe(materialize(), delay(500), dematerialize());
    }

    function unauthorized(): Observable<HttpEvent<any>> {
      return throwError(() => ({ status: 401, error: { message: 'Unauthorized' } })).pipe(materialize(), delay(500), dematerialize());
    }

    function basicDetails(account: any) {
      const { id, title, firstName, lastName, email, role, isVerified } = account;
      return { id, title, firstName, lastName, email, role, isVerified };
    }

    function isAdmin(): boolean {
      return isLoggedIn() && currentAccount()?.role === Role.Admin;
    }

    function isLoggedIn(): boolean {
      return !!currentAccount();
    }

    function currentAccount(): any {
      const authHeader = headers.get('Authorization');
      if (!authHeader?.startsWith('Bearer fake-jwt-token')) return null;
      const jwtToken = JSON.parse(atob(authHeader.split('.')[1]));
      const tokenExpired = Date.now() > jwtToken.exp * 1000;
      if (tokenExpired) return null;
      return accounts.find(x => x.id === jwtToken.id);
    }

    function idFromUrl(): string {
      const urlParts = url.split('/');
      return urlParts[urlParts.length - 1];
    }

    function newAccountId(): string {
      return (accounts.length ? Math.max(...accounts.map(x => parseInt(x.id))) + 1 : 1).toString();
    }

    function newToken(): string {
      // Use only URL-safe characters so the token survives query-string encoding/decoding
      const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
      let token = '';
      for (let i = 0; i < 32; i++) {
        token += chars.charAt(Math.floor(Math.random() * chars.length));
      }
      return token;
    }

    function generateJwtToken(account: any): string {
      const tokenPayload = { exp: Math.round(new Date(Date.now() + 15 * 60 * 1000).getTime() / 1000), id: account.id };
      return `fake-jwt-token.${btoa(JSON.stringify(tokenPayload))}`;
    }

    function generateRefreshToken(): string {
      return newToken();
    }

    function getRefreshToken(): string | null {
      return document.cookie.split(';').find(x => x.trim().startsWith('refreshToken='))?.split('=')[1] || null;
    }
  }
}

export const fakeBackendProvider = {
  provide: HTTP_INTERCEPTORS,
  useClass: FakeBackendInterceptor,
  multi: true
};
